import React, { useEffect, useState } from 'react'
import { useNavigate } from 'react-router-dom';
import { CCol, CForm, CButton } from "@coreui/react";
import FormInput from 'src/utils/FormInput';
import { createCategory, getCategoryData, updateCategory } from 'src/components/services/CategoryApi';
import GoBackComponent from 'src/utils/GoBackComponent';

const CategoryForm = (props) => {

    const { type, id } = props;
    const [formData, setFormData] = useState({ categoryName: "" });
    const [errors, setErrors] = useState({});
    const [errorMessage, setErrorMessage] = useState("");
    const navigate = useNavigate();

    useEffect(() => {
        if (type === "UPDATE") {
            fetchCategoryDataById(id);
        }
    }, [])

    const handleChange = (event) => {
        setFormData({ ...formData, [event.target.name]: event.target.value.trimStart().replace(/  +/g, ' ')});
    };

    const fetchCategoryDataById = async (id) => {
        let response = await getCategoryData(id);
        if (response ?.code === 200) {
            let data = {
                categoryName: response?.results?.name
            }
            setFormData(data);
        }
    }

    const validateForm = () => {
        let errors = {};
        let formIsValid = true;
        if (formData.categoryName === "") {
            errors['categoryName'] = "Please enter category name";
            formIsValid = false;
        }
        setErrors(errors);
        setTimeout(() => {
            setErrors({});
        }, 2000);
        return formIsValid;
    }

    const handleSubmit = async (event) => {
        event.preventDefault();
        if (validateForm()) {
            let postData = {
                name: formData?.categoryName?.trim()
            }
            let category = {};
            if (type === "CREATE") {
                category = await createCategory(postData);
            } else {
                postData.id = id;
                category = await updateCategory(postData);
            }
            if (category?.code === 200 || category.code === 201) {
                navigate('/category');
            }
            if (category?.code == 409) {
                setErrorMessage(category?.message);
            }
            setTimeout(() => {
                setErrorMessage("");
            }, 2000);
        }
    };

    return (
        <>
            <GoBackComponent goBackData={"category"} />
            <div className='customContainer'>
                <CForm className="row g-3">
                    <CCol md={8}>
                        <FormInput
                            value={formData.categoryName}
                            label={"Category Name"}
                            name={"categoryName"}
                            onChange={handleChange}
                            error={errors['categoryName']}
                        />
                        {errorMessage && <span style={{ color: "red" }}>{errorMessage}</span>}
                    </CCol>

                    <CCol md={12}>
                        <CButton color="primary" onClick={handleSubmit} className="d-block">
                            {props.type === "CREATE" ? "Create" : "Update"}
                        </CButton>
                    </CCol>
                </CForm>
            </div>
        </>
    );
}

export default CategoryForm;
